cd /home/bora/deha-crm/pilot-sandbox/ab-card/arm-c && node -e '
const ts = require("typescript");
const fs = require("fs");
const src = fs.readFileSync("DateTimePicker.tsx","utf8");
// forbidden-construct guards
const bad = [];
if (/\bimport\b/.test(src)) bad.push("import");
if (/\bexport\b/.test(src)) bad.push("export");
if (/useEffect/.test(src)) bad.push("useEffect");
if (/Math\.random|Date\.now/.test(src)) bad.push("nondeterministic");
if (/window\.DateTimePicker\s*=\s*DateTimePicker\b/.test(src)) bad.push("self-recursion");
console.log("guards:", bad.length ? "FAIL "+bad.join(",") : "PASS");
const out = ts.transpileModule(src, { compilerOptions: { module: ts.ModuleKind.None, jsx: ts.JsxEmit.React, target: ts.ScriptTarget.ES2019 }, reportDiagnostics: true });
console.log("diagnostics:", out.diagnostics.length);
out.diagnostics.forEach(d=>console.log(" -", ts.flattenDiagnosticMessageText(d.messageText,"\n")));
console.log("emit chars:", out.outputText.length);
'
